import java.util.*;

public class GradleTaskGraph {

    private final Map<String, List<String>> dependencies = new HashMap<>();

    public void addTask(String task) {
        dependencies.putIfAbsent(task, new ArrayList<>());
    }

    public void dependsOn(String task, String dependency) {
        // task depends on dependency (dependency runs first)
        addTask(task);
        addTask(dependency);
        dependencies.get(task).add(dependency);
    }

    public List<String> executionOrder(String targetTask) {
        // Return tasks in order they must execute (dependencies first)
        // Throw IllegalStateException if circular dependency detected
        return new ArrayList<>();
    }

    public static void main(String[] args) {
        GradleTaskGraph graph = new GradleTaskGraph();
        graph.dependsOn("build", "test");
        graph.dependsOn("test", "compile");
        graph.dependsOn("build", "jar");
        graph.dependsOn("jar", "compile");

        System.out.println(graph.executionOrder("build"));
    }
}

import java.util.*;

public class GradleScriptSimulator {

    private final List<String> plugins = new ArrayList<>();
    private final List<String> repositories = new ArrayList<>();
    private final List<String> dependencies = new ArrayList<>();

    public GradleScriptSimulator plugin(String pluginId) {
        plugins.add(pluginId);
        return this;
    }

    public GradleScriptSimulator repository(String repoUrl) {
        repositories.add(repoUrl);
        return this;
    }

    public GradleScriptSimulator dependency(String configuration, String gav) {
        // Store as 'configuration: gav'
        return this;
    }

    public String generateSummary() {
        // Return a summary string listing plugin count, repository count, dependency count
        return "";
    }

    public List<String> getDependencies() {
        return dependencies;
    }

    public static void main(String[] args) {
        GradleScriptSimulator script = new GradleScriptSimulator()
            .plugin("java")
            .plugin("org.springframework.boot")
            .repository("https://repo.maven.apache.org/maven2")
            .dependency("implementation", "org.springframework.boot:spring-boot-starter-web:3.0.0")
            .dependency("testImplementation", "org.junit.jupiter:junit-jupiter:5.9.0");

        System.out.println(script.generateSummary());
        System.out.println(script.getDependencies());
    }
}

import java.util.*;

public class IncrementalBuildTracker {

    private final Map<String, Long> lastBuildTimestamps = new HashMap<>();
    private final Map<String, Set<String>> taskInputFiles = new HashMap<>();

    public void registerTask(String taskName, Set<String> inputFiles) {
        taskInputFiles.put(taskName, new HashSet<>(inputFiles));
    }

    public void recordBuild(Map<String, Long> fileTimestamps) {
        // Store the current file timestamps as the last-build baseline
        lastBuildTimestamps.putAll(fileTimestamps);
    }

    public Map<String, String> checkTasks(Map<String, Long> currentTimestamps) {
        // For each registered task, check if any input file has a newer timestamp
        // Return map of taskName -> "UP-TO-DATE" or "NEEDS EXECUTION"
        return new HashMap<>();
    }

    public static void main(String[] args) {
        IncrementalBuildTracker tracker = new IncrementalBuildTracker();
        tracker.registerTask("compileJava", Set.of("Main.java", "Utils.java"));
        tracker.registerTask("processResources", Set.of("application.properties"));

        Map<String, Long> baseline = Map.of(
            "Main.java", 1000L, "Utils.java", 1000L, "application.properties", 1000L
        );
        tracker.recordBuild(baseline);

        Map<String, Long> current = Map.of(
            "Main.java", 2000L, "Utils.java", 1000L, "application.properties", 1000L
        );
        Map<String, String> result = tracker.checkTasks(current);
        System.out.println("compileJava: " + result.get("compileJava"));
        System.out.println("processResources: " + result.get("processResources"));
    }
}
